# DK GTV.  Gesten - Vejen
with detail = 2 {
    let gv = path("d2.dk.gtv");

    with railway = :first :pax :removed {
        with link = "line.dk.GTV" {
            track(gv[:ges.yv, :ges.yv + 3.31km]);
            line_label(:left:w, gv[:ges.yv + 3.3km] << 0.5mt, "GTV");
            track(gv[:ges.yv + 3.29km, :vej.yg]);
        }
    }
}

